+        if (t->inbuf_count > 0 && t->inbuf[last_idx] != '\n') {
+            t->inbuf_tail   = last_idx;
+            t->inbuf_count--;
+            enqueue_echo(term, '\b');
+            enqueue_echo(term, ' ');
+            enqueue_echo(term, '\b');
+        }
+        /* If buffer empty or last char is '\n', ignore the backspace */
+
+    } else {
+        /* Regular printable character */
+        if (t->inbuf_count < TERMINAL_MAX_LINE) {
+            t->inbuf[t->inbuf_tail] = c;
+            t->inbuf_tail  = (t->inbuf_tail + 1) % TERMINAL_MAX_LINE;
+            t->inbuf_count++;
+            enqueue_echo(term, c);
+        }
+        /* Buffer full: drop char (could optionally echo '\a' bell) */
+    }
+
+    /* Start transmitting if the hardware is idle */
+    if (!t->tx_busy)
+        try_transmit(term);
 }

